// Worked focus: httpsts-download-range-filename — Serve downloads with authorized resource lookup, content disposition, safe filenames, media type, validators, ranges, HEAD parity, byte accounting, and abort cleanup.
// Evidence: httpsts-worked-http-server-ts-responses-problems-streaming-5
// Competency: httpsts-worked-http-server-ts-responses-problems-streaming-5.
// Case 9036: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: saturate one tenant budget while another tenant remains serviceable.
function worked_http_server_ts_responses_problems_streaming_5(status: number, problemType: string, bufferedBytes: number, highWaterMark: number): { mediaType: string; continueWriting: boolean } {
  const mediaType = status >= 400 ? "application/problem+json" : "application/json";
  if (status >= 400 && problemType.length === 0) {
    return { mediaType: "invalid-problem", continueWriting: false };
  }
  const continueWriting = bufferedBytes >= 0 && bufferedBytes < highWaterMark;
  return { mediaType, continueWriting };
}

